VALUES
  ('judicial-cf446b4c-moex-00464', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於消滅時效與法律行為效力之敘述，何者錯誤？', '["民法第128條所稱之請求權可行使時，係指行使該請求權無障礙時而言，單純當事人主觀上不 知可行使權利，並非請求權可行使之障礙", "時效不完成係指一定行為之發生，將導致時效不完成，且嗣後將重新起算時效", "無權處分之效力未定，應以物權行為效力未定，債權行為應屬有效", "無權代理之效力未定，則無權代理所為之債權行為與物權行為均屬效力未定 20420 20520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00465', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '關於附條件之法律行為，下列敘述，何者錯誤？', '["附停止條件之法律行為，於條件成就時，當然發生效力", "附解除條件之法律行為，於條件成就時，不待當事人另以意思表示為終止，即失效力", "約定解除權之行使，須以意思表示為之者，與附解除條件相同", "因條件成就而受不利益之當事人，如以不正當行為阻其條件之成就者，視為條件已成就"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00466', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於不當得利之敘述，何者正確？', '["甲擅自使用乙所有，但長年閒置且無人居住之A屋，此時乙並未受有損害，故不構成不當得利", "甲誤認乙對第三人丙之新臺幣（下同）5萬元債務，為自己之債務，故向丙為5萬元之清償， 嗣後甲得向丙請求返還", "甲雖知自己對乙之10萬元債務尚未到清償期，但仍於清償期屆至前，將本金及利息如數給付。 甲於給付後隔日若突須用錢，均得向乙請求返還", "甲不知自己從乙處受領 10 顆蘋果乃無法律上之原因。若蘋果已全數食用完畢，則甲應對乙償 還其價額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00467', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲駕車超速致失控撞上路過之上班族乙，下列敘述，何者錯誤？', '["乙傷重不治時，乙之祖父丙得向甲請求非財產上損害賠償", "乙傷重不治時，乙之父丁得向甲請求非財產上損害賠償", "乙經入院治療1個月後，傷重不治時，為乙支出醫療費用之友人戊，得向甲請求損害賠償", "乙嗣後經判定為植物人狀態時，與乙感情深厚之母己基於身分法益受不法侵害而情節重大者， 得向甲請求非財產上損害賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00468', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲以優厚報酬延請乙為其建造A屋，作為新婚處所，雙方並約定由甲自行提供建屋所需之全部材 料。下列敘述，何者錯誤？', '["若新造之A屋有數面牆面的油漆輕微不均，則甲不得解除契約", "若因乙之設計不當，致新造之A屋異常歪斜，經專業機構鑑定認有實質上之倒塌危險，則甲仍 不得解除契約", "若甲於A屋交付後第2年年底，始發現地下室牆角有滲水問題，則甲仍得對乙主張負瑕疵擔保 責任", "若甲於A屋交付後第1年6月底，即已發現地下室牆角有滲水問題，則甲須於第2年6月底屆 滿前，行使其瑕疵擔保之各項權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00469', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲有A屋及其所座落之B地，甲僅將該A屋出售並移轉所有權予乙。不久，甲因病身亡，由其 子丙繼承，丙復將B地出售並移轉所有權予丁。下列敘述，何者正確？', '["A屋座落於B地之上，故甲不得僅將A屋出售予乙，須連同其所座落之B地一同出售", "丙雖繼承甲之財產，若未經繼承登記，仍非B地之所有人", "丙已出售並移轉B地所有權予丁，土地所有人丁得對乙請求拆屋還地", "房屋受讓人乙得於A屋之可使用年限內，對土地受讓人丁主張有租賃關係存在 20420 20520"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00470', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲有A屋1間，出賣予乙並交付之，隨後甲又立即將A屋出賣予出價更高之丙，並辦理移轉登記 完畢。下列敘述，何者錯誤？', '["乙取得A屋所有權", "丙取得A屋所有權", "乙得向甲請求損害賠償", "丙得向乙請求返還A屋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00471', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲在乙之土地上設定普通地上權，約定期間20年，甲在該地上蓋商業大樓1棟。13年後，該大 樓因甲之重大過失而焚燬。下列敘述，何者正確？', '["甲之地上權消滅", "甲之地上權期間，重新起算", "甲得請求減免租金", "甲得在原地重建大樓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00472', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲有1間合法工廠，因向乙借錢周轉而將工廠設定普通抵押權予乙，後來又緊臨工廠增設獨立倉 庫1間，當甲無法清償債務時，乙實行抵押權時，就該增建之倉庫應如何處理？', '["乙得聲請成為共有人", "乙得聲請法院併付拍賣", "乙享有法定抵押權", "乙享有法定地上權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00473', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於民法袋地通行權之敘述，何者錯誤？', '["土地與公路無適宜之聯絡，致不能為通常之使用時，除因土地所有人之任意行為所生者外，土 地所有人得通行周圍地以至公路", "有通行權人應於通行之必要範圍內，應擇其損害最少之處所及方法為之", "有通行權人必要時，得開設馬路，但對於通行地因此所受損害，應支付償金", "因土地一部轉讓而造成袋地者，得通行讓與人或受讓人之所有土地，但必須支付償金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
